import os
import fnmatch
from pathlib import Path

IGNORE_PATTERNS = [".git", "node_modules", "__pycache__", "*.min.js", "dist/", "build/"]

def collect_files(root: str, max_bytes: int = 1_000_000) -> dict[str, str]:
    """Walk the repo and return {relative_path: content} for text files."""
    result = {}
    for dirpath, dirnames, filenames in os.walk(root):
        # Prune ignored directories in-place
        dirnames[:] = [
            d for d in dirnames
            if not any(fnmatch.fnmatch(d, pat) for pat in IGNORE_PATTERNS)
        ]
        for fname in filenames:
            fpath = os.path.join(dirpath, fname)
            rel = os.path.relpath(fpath, root)
            if any(fnmatch.fnmatch(rel, pat) for pat in IGNORE_PATTERNS):
                continue
            try:
                with open(fpath, "r", encoding="utf-8", errors="ignore") as f:
                    text = f.read(max_bytes)
                result[rel] = text
            except OSError:
                pass
    return result

import json
from anthropic import Anthropic

client = Anthropic()

TOOLS = [
    {
        "name": "read_file",
        "description": "Read a file by relative path.",
        "input_schema": {"type": "object", "properties": {"path": {"type": "string"}}, "required": ["path"]},
    },
    {
        "name": "search_code",
        "description": "Search repo for files containing a keyword.",
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string"},
                "top_k": {"type": "integer", "default": 5},
            },
            "required": ["query"],
        },
    },
    {
        "name": "write_file",
        "description": "Write content to a file.",
        "input_schema": {"type": "object", "properties": {"path": {"type": "string"}, "content": {"type": "string"}}, "required": ["path", "content"]},
    },
]

def run_tool(name: str, inputs: dict, repo_root: str, files: dict[str, str]) -> str:
    if name == "read_file":
        return files.get(inputs["path"], f"File not found: {inputs['path']}")
    if name == "search_code":
        hits = keyword_search(files, inputs["query"], top_k=inputs.get("top_k", 5))
        return json.dumps(hits)
    if name == "write_file":
        full_path = os.path.join(repo_root, inputs["path"])
        Path(full_path).parent.mkdir(parents=True, exist_ok=True)
        with open(full_path, "w") as f:
            f.write(inputs["content"])
        return f"Wrote {len(inputs['content'])} bytes to {inputs['path']}"
    return f"Unknown tool: {name}"

def coding_agent(task: str, repo_root: str) -> str:
    files = collect_files(repo_root)
    initial_ctx = build_context_for_task(task, repo_root)
    system = f"You are a coding agent.\n\nRepository context:\n\n{initial_ctx}"
    messages = [{"role": "user", "content": task}]

    while True:
        response = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=4096,
            system=system,
            tools=TOOLS,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            for block in response.content:
                if hasattr(block, "text"):
                    return block.text
            return ""

        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                result = run_tool(block.name, block.input, repo_root, files)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result,
                })
        messages.append({"role": "user", "content": tool_results})

def safe_wrap_file(path: str, content: str) -> str:
    """Wrap file content in delimiters that mark it as untrusted input."""
    return f"""<file path="{path}" trust="untrusted">
{content}
</file>"""

